import json, re
from anthropic import Anthropic

_judge_client = Anthropic()

def score_exact(output: str, golden: str) -> float:
    """Exact string match after normalizing whitespace."""
    return 1.0 if output.strip() == golden.strip() else 0.0

def score_json_schema(output: str, required_keys: list[str]) -> float:
    """Partial credit for JSON outputs: fraction of required keys present and non-null."""
    try:
        data = json.loads(output)
        present = sum(1 for k in required_keys if data.get(k) is not None)
        return present / len(required_keys)
    except json.JSONDecodeError:
        return 0.0

def score_llm_judge(output: str, task_desc: str, rubric: str) -> float:
    """Use a judge model to score free-form outputs on a 0-3 rubric."""
    prompt = f"""You are an impartial evaluator. Score the following model output
on a 0-3 scale using the rubric below. Reply with a single integer: 0, 1, 2, or 3.

Task description: {task_desc}
Rubric:
{rubric}

Model output:
{output}

Score (0-3):"""
    resp = _judge_client.messages.create(
        model="claude-haiku-4-5-20251001",  # cheap judge for bulk scoring
        max_tokens=4,
        messages=[{"role": "user", "content": prompt}],
    )
    text = resp.content[0].text.strip()
    match = re.search(r"[0-3]", text)
    return int(match.group()) / 3.0 if match else 0.0  # normalize to [0, 1]
